import { AgendaService } from '../../services/agenda.service.js';
import type { AgendaEvent } from '@motivation/shared';
import type { AgendaList } from './agenda-list/agenda-list.component.js';
import './agenda-list/agenda-list.component.js';

export class AgendaRenderer {
    private container: HTMLElement;
    private agendaList: AgendaList;

    constructor(container: HTMLElement) {
        this.container = container;
        this.agendaList = document.createElement('agenda-list') as AgendaList;
        this.container.appendChild(this.agendaList);
    }

    async init() {
        this.showLoading();
        try {
            const events = await AgendaService.fetchEvents();
            this.renderEvents(events);
        } catch (error) {
            console.error('Failed to load agenda', error);
            this.showError('Failed to load agenda.');
        } finally {
            this.hideLoading();
        }
    }

    renderEvents(events: AgendaEvent[]) {
        this.agendaList.events = events;
    }

    showLoading() {
        const loader = document.getElementById('loading-indicator');
        if (loader) loader.hidden = false;
    }

    hideLoading() {
        const loader = document.getElementById('loading-indicator');
        if (loader) loader.hidden = true;
    }

    showError(message: string) {
        const errorElement = document.getElementById('error-message');
        if (errorElement) {
            errorElement.textContent = message;
            errorElement.hidden = false;
            setTimeout(() => {
                errorElement.hidden = true;
            }, 5000);
        }
    }
}
