import stylesText from './agenda-item.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div class="agenda-item">
        <div class="agenda-time">
            <span class="agenda-date" id="date"></span>
            <span class="agenda-hours" id="hours"></span>
        </div>
        <div class="agenda-details" id="details">
            <h3 class="agenda-summary" id="summary"></h3>
        </div>
    </div>
`;

export class AgendaItem extends HTMLElement {
    static get observedAttributes() {
        return ['data-summary', 'data-start', 'data-end', 'data-location'];
    }

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    attributeChangedCallback(_name: string, oldValue: string | null, newValue: string | null) {
        if (oldValue === newValue) return;
        this.update();
    }

    private isDateOnly(dateString: string): boolean {
        return !dateString.includes('T');
    }

    private parseDateTime(dateString: string): Temporal.ZonedDateTime | null {
        if (this.isDateOnly(dateString)) {
            return null;
        }

        return Temporal.Instant.from(dateString).toZonedDateTimeISO(Temporal.Now.timeZoneId());
    }

    private formatTime(dateString: string | undefined | null): string {
        if (!dateString) return '';
        if (this.isDateOnly(dateString)) return 'All day';

        const zdt = this.parseDateTime(dateString);
        if (!zdt) return 'All day';
        return zdt.toLocaleString(undefined, { hour: '2-digit', minute: '2-digit' });
    }

    private formatDate(dateString: string | undefined | null): string {
        if (!dateString) return '';

        if (this.isDateOnly(dateString)) {
            const date = Temporal.PlainDate.from(dateString);
            return date.toLocaleString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
        }

        const zdt = this.parseDateTime(dateString);
        if (!zdt) return '';
        return zdt.toLocaleString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
    }

    private update() {
        const shadow = this.shadowRoot!;
        const start = this.dataset.start;
        const end = this.dataset.end;

        shadow.getElementById('date')!.textContent = this.formatDate(start);
        const isAllDay = start ? this.isDateOnly(start) : false;
        shadow.getElementById('hours')!.textContent = isAllDay
            ? this.formatTime(start)
            : `${this.formatTime(start)} - ${this.formatTime(end)}`;
        shadow.getElementById('summary')!.textContent = this.dataset.summary ?? '';

        // Handle optional location element
        const details = shadow.getElementById('details')!;
        let locationEl = shadow.getElementById('location');
        if (this.dataset.location) {
            if (!locationEl) {
                locationEl = document.createElement('p');
                locationEl.id = 'location';
                locationEl.classList.add('agenda-location');
                details.appendChild(locationEl);
            }
            locationEl.textContent = `📍 ${this.dataset.location}`;
        } else if (locationEl) {
            locationEl.remove();
        }
    }
}

customElements.define('agenda-item', AgendaItem);
