import type { AgendaEvent } from '@motivation/shared';
import { AgendaItem } from './agenda-item/agenda-item.component.js';
import stylesText from './agenda-list.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div id="list-container"></div>
`;

export class AgendaList extends HTMLElement {
    private _events: AgendaEvent[] = [];

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    set events(events: AgendaEvent[]) {
        this._events = events;
        this.render();
    }

    connectedCallback() {
        this.render();
    }

    render() {
        const container = this.shadowRoot!.getElementById('list-container')!;
        container.replaceChildren();

        if (this._events.length === 0) {
            const emptyDiv = document.createElement('div');
            emptyDiv.textContent = 'No upcoming events.';
            emptyDiv.classList.add('empty-state');
            container.appendChild(emptyDiv);
            return;
        }

        const list = document.createElement('div');
        list.classList.add('agenda-list');

        this._events.forEach(event => {
            const item = document.createElement('agenda-item') as AgendaItem;
            item.dataset.summary = event.summary ?? '';
            item.dataset.start = event.start ?? '';
            item.dataset.end = event.end ?? '';
            if (event.location) item.dataset.location = event.location;
            list.appendChild(item);
        });

        container.appendChild(list);
    }
}

customElements.define('agenda-list', AgendaList);
